      <Pagination
        currentPage={page}
        totalPages={batchList?.total_pages ?? 1}
        onPageChange={setPage}
      />
      {/* Hidden pollers */}
      {activeBatches.map((b) => (
        <BatchPoller
          key={b.id}
          batchRunId={b.id}
          listStatus={b.status}
          onStatusChange={() => refetch()}
          onTerminal={(status) => {
            if (!completedBatchRunIds.has(b.id)) {
              setCompletedBatchRunIds((prev) => new Set(prev).add(b.id));
              const isSuccess = ["success", "completed"].includes(status.toLowerCase());
              toast[isSuccess ? "success" : "error"](
                `Batch ${b.batch_name} ${isSuccess ? "completed" : "failed"}`,
              );
              notifyBatchComplete(b.batch_name, isSuccess);
              refetch();
            }
          }}
        />
      ))}
    </div>
  );
}

function BatchPoller({
  batchRunId,
  listStatus,
  onStatusChange,
  onTerminal,
}: {
  batchRunId: string;
  listStatus: string;
  onStatusChange: () => void;
  onTerminal: (status: string) => void;
}) {
  const queryClient = useQueryClient();
  const { data } = useBatchRunStatus(batchRunId);
  const lastNotifiedStatus = useRef<string | null>(null);
  const status = data?.status?.toLowerCase();
  const normalizedListStatus = listStatus?.toLowerCase();

  useEffect(() => {
    if (!status || status === lastNotifiedStatus.current) {
      return;
    }

    lastNotifiedStatus.current = status;
    const terminal =
      status === "success" || status === "failed" || status === "completed" || status === "failure";

    if (terminal && data) {
      onTerminal(data.status);
      queryClient.invalidateQueries({ queryKey: ["batch", "status", batchRunId] });
      return;
    }

    if (status !== normalizedListStatus) {
      onStatusChange();
    }
  }, [status, normalizedListStatus, data, onTerminal, onStatusChange, queryClient, batchRunId]);

  return null;
}

